"""Section 04 — Autocorrelation of Δmid and |Δmid| per product/day.

Sign-AC(1) on Δmid is a fast diagnostic for tick-level mean reversion (negative
values) vs momentum (positive). |Δmid| AC(1) measures volatility clustering.
"""
from __future__ import annotations

import numpy as np
import pandas as pd
from _common import (fmt_section_header, per_product_per_day_records, save_outputs)


def _ac1(x: np.ndarray) -> float:
    if len(x) < 3:
        return float("nan")
    a = x - x.mean()
    denom = float(np.dot(a, a))
    if denom == 0:
        return float("nan")
    return float(np.dot(a[:-1], a[1:]) / denom)


